#nullable enable // autogenerated

using MVZ2.Vanilla.Entities;
using MVZ2Logic.Entities;
using MVZ2.Vanilla.Properties;
using PVZEngine.Definitions;
using PVZEngine.Entities;
using PVZEngine.Modifiers;

namespace MVZ2.GameContent.Entities
{
    [AutoEntityBehaviourDefinition(VanillaEntityBehaviourNames.faction)]
    public class FactionBehaviour : EntityBehaviourDefinition
    {
        public FactionBehaviour(string nsp, string name) : base(nsp, name)
        {
            AddModifier(new BooleanModifier(EngineEntityProps.FLIP_X, PROP_FLIP_X));
        }
        public override void Init(Entity entity)
        {
            base.Init(entity);
            UpdateFlipX(entity);
        }
        public override void Update(Entity entity)
        {
            base.Update(entity);
            UpdateFlipX(entity);
        }
        private void UpdateFlipX(Entity entity)
        {
            int targetFaction = entity.GetFaction();
            var faceRight = targetFaction == entity.Level.Option.LeftFaction;
            entity.SetProperty(PROP_FLIP_X, entity.FaceLeftAtDefault() == faceRight);
        }

        public static readonly VanillaEntityPropertyMeta<bool> PROP_FLIP_X = new VanillaEntityPropertyMeta<bool>("FlipX");
    }
}
